qry:select.qry:xquery:
					for $r in sql('
			SELECT 
				PER01_PERSONAL.d_ape_y_nom, 
				PER02_PERSONAL_EMP.oi_personal_emp, 
				PER02_PERSONAL_EMP.e_numero_legajo, 
				PER02_PERSONAL_EMP.f_ingreso,
				PER11_TIPOS_PERS.d_tipo_personal, 
				ORG03_EMPRESAS.c_empresa,
				ORG08_CS_COSTO.c_centro_costo,
				ORG08_CS_COSTO.d_centro_costo				
			FROM 
				PER02_PERSONAL_EMP, 
				ORG03_EMPRESAS, 
				PER01_PERSONAL, 
				PER11_TIPOS_PERS, 
				ORG08_CS_COSTO
      JOIN
				PER02_PERSONAL_EMP.oi_personal INNER PER01_PERSONAL.oi_personal,
        PER02_PERSONAL_EMP.oi_empresa INNER ORG03_EMPRESAS.oi_empresa,
        PER02_PERSONAL_EMP.oi_tipo_personal INNER PER11_TIPOS_PERS.oi_tipo_personal,
        PER02_PERSONAL_EMP.oi_ctro_costo_ult INNER ORG08_CS_COSTO.oi_centro_costo
    	WHERE	1=1
				{%? (#SOURCE:@EMPRESA!='')	{% AND PER02_PERSONAL_EMP.oi_empresa ={#SOURCE:@EMPRESA} %} {% %} %}
				{%? (#SOURCE:@TIPO_PER!='')	{% AND PER02_PERSONAL_EMP.oi_tipo_personal ={#SOURCE:@TIPO_PER} %} {% %} %}
				{%? (string(#SOURCE:LEGAJOS/LEGAJO/@id)!='') {% AND PER02_PERSONAL_EMP.oi_personal_emp in ({%=string(#SOURCE:LEGAJOS/LEGAJO/@id) %}) %} {%  %} %}
    		{%? (#SOURCE:@F_HASTA!='') {% AND PER02_PERSONAL_EMP.f_ingreso < {#SOURCE:@F_HASTA} %} {% %} %}
    		{%? (#SOURCE:@F_DESDE!='') {% AND PER02_PERSONAL_EMP.f_ingreso > {#SOURCE:@F_DESDE} %} {% %} %} 
    		{%? (#SOURCE:@oi_indic_activo!='') {% AND PER02_PERSONAL_EMP.oi_indic_activo = {#SOURCE:@oi_indic_activo} %} {% %} %}
    	  {%? (#SOURCE:@oi_ctro_costo!='')	{% AND PER02_PERSONAL_EMP.oi_ctro_costo_ult ={#SOURCE:@oi_ctro_costo} %} {% %} %} 
			ORDER BY 
      	{%? (#SOURCE:@ATRIB_ORDEN1!='')	{% {%=#SOURCE:@ATRIB_ORDEN1%} {%? (#SOURCE:@ORDEN1!='') {% {%=#SOURCE:@ORDEN1%}, %} {% ASC, %}	%} %} {% %} %}
				{%? (#SOURCE:@ATRIB_ORDEN2!='')	{% {%=#SOURCE:@ATRIB_ORDEN2%} {%? (#SOURCE:@ORDEN2!='') {% {%=#SOURCE:@ORDEN2%}, %} {% ASC, %}	%} %} {% %} %}
				{%? (#SOURCE:@ATRIB_ORDEN3!='')	{% {%=#SOURCE:@ATRIB_ORDEN3%} {%? (#SOURCE:@ORDEN3!='') {% {%=#SOURCE:@ORDEN3%}, %} {% ASC, %}	%} %} {% %} %}
				{%? (#SOURCE:@ATRIB_ORDEN4!='')	{% {%=#SOURCE:@ATRIB_ORDEN4%} {%? (#SOURCE:@ORDEN4!='') {% {%=#SOURCE:@ORDEN4%}, %} {% ASC, %}	%} %} {% %} %}
				{%? (#SOURCE:@ATRIB_ORDEN5!='')	{% {%=#SOURCE:@ATRIB_ORDEN5%} {%? (#SOURCE:@ORDEN5!='') {% {%=#SOURCE:@ORDEN5%}, %} {% ASC, %}	%} %} {% %} %}
				oi_personal_emp ASC
			')/ROWS/ROW
